+        let b = SchemaId {
+            namespace: "a".to_string(),
+            name: "b".to_string(),
+            version: Version::new(0, 0, 0),
+        };
+        // Under the old encoding both became "ab:@0.0.0" / "a:b@0.0.0" — different
+        // here, but the broader principle is that lengths participate in the hash.
